<span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">GPIO_ISTAT_ISTAT8</span>          <span class="token expression"><span class="token function">BIT</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">)</span>                </span><span class="token comment">/*!&lt; pin 8 input status */</span></span>
